Javascript.validate:
// defect UAT 883
var dateOrigOrder = Services.getValue(DateOfOriginalAO.dataBinding);
var dateOrigOrderObj = CaseManUtils.isBlank(dateOrigOrder) ? null : CaseManUtils.createDate(dateOrigOrder);
var todayDateObj = CaseManUtils.createDate(getTodaysDate());
var errCode = null;
if(dateOrigOrderObj != null){
	var comparison = CaseManUtils.compareDates(dateOrigOrderObj, todayDateObj);
	if(comparison == -1){
		errCode = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
	}     
}
return errCode;
